import axios from 'axios';
import React, { useEffect, useState } from 'react';

const STATUS_LABELS = {
  'Novo': 'Novo',
  'Retorno': 'Retorno',
  'Recepção': 'Recepção',
};
const STATUS_COLORS = {
  'Novo': "bg-teal-300 text-white",
  'Retorno': "bg-blue-300 text-white",
  'Recepção': "bg-red-300 text-white",
};

export default function ListaAgendamentos({ onEditar }) {
  const [agendamentos, setAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/agendamentos')
      .then((res) => {
        setAgendamentos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar agendamentos:', err);
        setCarregando(false);
      });
  }, []); // <--- Removeu reloadKey

  const handleDeletar = (id) => {
    if (window.confirm('Tem certeza que deseja deletar este agendamento?')) {
      axios.delete(`/api/agendamentos/${id}`)
        .then(() => {
          setAgendamentos(agendamentos.filter(a => a.id !== id));
        })
        .catch(() => alert('Erro ao deletar agendamento'));
    }
  };

  if (carregando) return <p>Carregando agendamentos...</p>;
  if (agendamentos.length === 0) return <p>Nenhum agendamento cadastrado.</p>;

  return (
    <div className="bg-white rounded-2xl shadow p-0 overflow-x-auto mt-6">
      <table className="min-w-full rounded-2xl">
        <thead>
          <tr className="border-b">
            <th className="px-6 py-4 text-left font-semibold">Operador</th>
            <th className="px-6 py-4 text-left font-semibold">Auxiliar</th>
            <th className="px-6 py-4 text-left font-semibold">Disciplina</th>
            <th className="px-6 py-4 text-left font-semibold">Paciente</th>
            <th className="px-6 py-4 text-left font-semibold">Telefone</th>
            <th className="px-6 py-4 text-left font-semibold">Status</th>
            {/* <th className="px-6 py-4"></th> */}
          </tr>
        </thead>
        <tbody>
          {agendamentos.map((ag, idx) => (
            <tr key={ag.id || idx} className="border-b last:border-b-0 hover:bg-gray-50">
              <td className="px-6 py-4">{ag.operadorNome}</td>
              <td className="px-6 py-4">{ag.auxiliarNome}</td>
              <td className="px-6 py-4">{ag.disciplinaNome}</td>
              <td className="px-6 py-4">{ag.pacienteNome}</td>
              <td className="px-6 py-4">{ag.telefone}</td>
              <td className="px-6 py-4">
                <span className={
                    "inline-block px-4 py-1 rounded-full font-semibold text-sm " +
                    (STATUS_COLORS[ag.statusLabel] || "bg-gray-200 text-gray-700")
                  }
                >
                  {ag.statusLabel}
                </span>
              </td>
              {/* <td>
                <button onClick={() => onEditar(ag)} className="text-blue-600 hover:underline">Editar</button>
              </td> */}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
